import streamlit as st
import pandas as pd
import matplotlib.pyplot as plt
import json
from streamlit_echarts import st_echarts

st.title("Native ECharts in Streamlit - External JSON files")


data = {
    'Nome' : ['Ana', 'Bruno', 'Carlos'],
    'Idade' : [23, 35, 45],
    'Salario' : [5000, 7000, 9000]
}

df = pd.DataFrame(data)

st.dataframe(df)
st.table(df)


# Grafico 1 - Barras
jsonfile1 = "ExemploBarras.json"

with open(jsonfile1, "r", encoding="utf-8") as f:
    chart_options = json.load(f)

st_echarts(options=chart_options, height="600px") 


